default float bulkScore(int[] nodes, float[] scores, int numNodes) throws IOException {
    float max = Float.NEGATIVE_INFINITY;
    for (int i = 0; i < numNodes; i++) {
      scores[i] = score(nodes[i]);
      max = Math.max(max, scores[i]);
    }
    return max;
  }
